class Solution:
    def minFallingPathSum(self, matrix):
        n = len(matrix)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(None)
        def best(r, c):
            if c < 0 or c >= n:
                return float('inf')
            if r == 0:
                return matrix[0][c]
            return matrix[r][c] + min(best(r - 1, c - 1), best(r - 1, c), best(r - 1, c + 1))
        return min(best(n - 1, c) for c in range(n))

