class Solution:
    def minFallingPathSum(self, matrix):
        n = len(matrix)
        row = matrix[0][:]
        for r in range(1, n):
            nxt = [0] * n
            for c in range(n):
                best = row[c]
                if c > 0:
                    best = min(best, row[c - 1])
                if c < n - 1:
                    best = min(best, row[c + 1])
                nxt[c] = matrix[r][c] + best
            row = nxt
        return min(row)

