var minFallingPathSum = function(matrix) {
    const n = matrix.length;
    let row = matrix[0].slice();
    for (let r = 1; r < n; r++) {
        const nxt = new Array(n);
        for (let c = 0; c < n; c++) {
            let best = row[c];
            if (c > 0) best = Math.min(best, row[c - 1]);
            if (c < n - 1) best = Math.min(best, row[c + 1]);
            nxt[c] = matrix[r][c] + best;
        }
        row = nxt;
    }
    return Math.min(...row);
};
